def bin2dec(x):
    """
    Convert binary string to decimal number.
    For instance: '11' -> 3
    """
    return int(x, 2)

def oct2dec(x):
    """
    Convert octal string to decimal number.
    For instance: '11' -> 9
    """
    return int(x, 8)

def hex2dec(x):
    """
    Convert hexadecimal string to decimal number.
    For instance: '1a' -> 26
    """
    return int(x, 16)

