import time
from functools import wraps

def retry_on_exception(max_retries=3, delay=1, exceptions=(Exception,)):
    """
    Decorator to retry a function if it raises specified exceptions.

    Args:
        max_retries (int): Maximum number of retry attempts.
        delay (float): Seconds to wait between retries.
        exceptions (tuple): Exception types to catch and retry on.

    Returns:
        function: Decorated function.
    """
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(max_retries + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    if attempt == max_retries:
                        raise
                    time.sleep(delay)
            return None
        return wrapper
    return decorator
